const express = require('express');

const app = express();

function getClientIp(req) {
  const xfwd = req.headers['x-forwarded-for'];
  if (typeof xfwd === 'string' && xfwd.length) return xfwd.split(',')[0].trim();
  if (Array.isArray(xfwd) && xfwd.length) return xfwd[0].trim();
  return req.socket?.remoteAddress || req.ip || 'unknown';
}

app.get('/activity', (req, res) => {
  const action = typeof req.query.action === 'string' ? req.query.action.trim() : '';
  if (!action) {
    return res.status(400).json({ ok: false, error: 'Missing required query parameter: action' });
  }

  const ts = new Date().toISOString();
  const ip = getClientIp(req);
  const ua = req.headers['user-agent'] || '';

  console.log(`[${ts}] action="${action}" ip="${ip}" ua="${ua}"`);

  res.json({ ok: true });
});

const port = Number(process.env.PORT) || 3000;
app.listen(port, () => {
  console.log(`Audit logger listening on port ${port}`);
});